import { create } from 'zustand';
import { FinalReport } from '@/services/ai/state';

export type LoadingStage = 
  | 'idle'
  | 'validating'
  | 'researching'
  | 'financials'
  | 'news'
  | 'swot'
  | 'risk'
  | 'decision'
  | 'report'
  | 'complete'
  | 'error';

interface ResearchState {
  query: string;
  setQuery: (query: string) => void;

  isAnalyzing: boolean;
  loadingStage: LoadingStage;
  error: string | null;
  report: FinalReport | null;

  analyzeCompany: (companyName: string) => Promise<void>;
  reset: () => void;
  cancelRequest: () => void;
}

// Global abort controller to handle cancellations
let abortController: AbortController | null = null;

const stages: LoadingStage[] = [
  'validating',
  'researching',
  'financials',
  'news',
  'swot',
  'risk',
  'decision',
  'report',
  'complete'
];

export const useResearchStore = create<ResearchState>((set, get) => ({
  query: '',
  setQuery: (query: string) => set({ query }),

  isAnalyzing: false,
  loadingStage: 'idle',
  error: null,
  report: null,

  cancelRequest: () => {
    if (abortController) {
      abortController.abort();
      abortController = null;
    }
    set({ isAnalyzing: false, loadingStage: 'idle' });
  },

  reset: () => {
    get().cancelRequest();
    set({ query: '', error: null, report: null, loadingStage: 'idle' });
  },

  analyzeCompany: async (companyName: string) => {
    // Cancel previous request if any
    get().cancelRequest();

    set({ 
      isAnalyzing: true, 
      loadingStage: 'validating', 
      error: null, 
      report: null,
      query: companyName 
    });

    abortController = new AbortController();

    // Setup a simulated timeline progression to give user feedback
    // In a real WebSocket setup this would be event-driven.
    // For HTTP, we fake the timeline based on time elapsed.
    let currentStageIndex = 0;
    const stageInterval = setInterval(() => {
      currentStageIndex++;
      if (currentStageIndex < stages.length - 1) { // Don't reach 'complete' via interval
        set({ loadingStage: stages[currentStageIndex] });
      } else {
        clearInterval(stageInterval);
      }
    }, 4500); // Progress every 4.5s

    try {
      const response = await fetch('/api/analyze', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ companyName }),
        signal: abortController.signal,
      });

      clearInterval(stageInterval);

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || data.details?.[0] || 'An error occurred during analysis.');
      }

      set({ 
        report: data as FinalReport, 
        loadingStage: 'complete', 
        isAnalyzing: false 
      });

    } catch (error: any) {
      clearInterval(stageInterval);
      if (error.name === 'AbortError') {
        console.log('Request cancelled');
        return;
      }
      set({ 
        error: error.message || 'Failed to connect to the server.',
        loadingStage: 'error',
        isAnalyzing: false 
      });
    } finally {
      abortController = null;
    }
  },
}));

"use client";

import { Search, Loader2, ArrowRight } from "lucide-react";
import { useState, KeyboardEvent } from "react";
import { useResearchStore } from "@/store/useResearchStore";

export function SearchBar() {
  const [localQuery, setLocalQuery] = useState("");
  const { analyzeCompany, isAnalyzing } = useResearchStore();

  const handleSearch = () => {
    if (!localQuery.trim() || isAnalyzing) return;
    analyzeCompany(localQuery.trim());
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      handleSearch();
    }
  };

  return (
    <div className="relative group w-full max-w-2xl mx-auto flex items-center mt-8">
      <div className="absolute inset-0 bg-gradient-to-r from-primary/10 to-primary/5 rounded-2xl blur-xl opacity-50 group-hover:opacity-100 transition-opacity duration-500" />
      <div className="relative flex w-full items-center bg-card/50 backdrop-blur-sm border border-border/50 rounded-2xl p-2 shadow-sm transition-all focus-within:shadow-md focus-within:border-primary/50">
        <Search className="ml-3 h-5 w-5 text-muted-foreground" />
        <input
          type="text"
          value={localQuery}
          onChange={(e) => setLocalQuery(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={isAnalyzing}
          placeholder="Enter a company name (e.g., NVIDIA, Apple, Reliance)..."
          className="flex-1 bg-transparent border-none outline-none px-4 py-3 text-foreground placeholder:text-muted-foreground disabled:opacity-50 text-lg"
        />
        <button
          onClick={handleSearch}
          disabled={!localQuery.trim() || isAnalyzing}
          className="flex items-center justify-center bg-primary text-primary-foreground h-12 w-12 rounded-xl transition-all hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100 disabled:cursor-not-allowed"
          aria-label="Analyze Company"
        >
          {isAnalyzing ? (
            <Loader2 className="h-5 w-5 animate-spin" />
          ) : (
            <ArrowRight className="h-5 w-5" />
          )}
        </button>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { useResearchStore, LoadingStage } from "@/store/useResearchStore";
import { CheckCircle2, Circle, Loader2 } from "lucide-react";

const STAGES: { id: LoadingStage; label: string; description: string }[] = [
  { id: "validating", label: "Validating Input", description: "Verifying company identity and ticker." },
  { id: "researching", label: "Company Research", description: "Gathering profile, model, and overview." },
  { id: "financials", label: "Financial Analysis", description: "Evaluating revenue, margins, and valuation." },
  { id: "news", label: "News Analysis", description: "Synthesizing recent catalysts and sentiment." },
  { id: "swot", label: "SWOT Analysis", description: "Identifying Strengths, Weaknesses, Opportunities, Threats." },
  { id: "risk", label: "Risk Assessment", description: "Evaluating operational, financial, and macro risks." },
  { id: "decision", label: "Investment Decision", description: "Calculating score and synthesizing recommendation." },
  { id: "report", label: "Report Generation", description: "Assembling final JSON report payload." },
];

export function AnalysisTimeline() {
  const { loadingStage, query } = useResearchStore();

  const getCurrentIndex = () => {
    return STAGES.findIndex(s => s.id === loadingStage);
  };

  const currentIndex = getCurrentIndex();

  return (
    <div className="w-full max-w-2xl mx-auto my-12 p-8 rounded-3xl bg-card border border-border shadow-sm">
      <div className="mb-8">
        <h3 className="text-2xl font-semibold tracking-tight">
          Analyzing {query || "Company"}...
        </h3>
        <p className="text-muted-foreground mt-2">
          Autonomous agents are currently executing the research workflow.
        </p>
      </div>

      <div className="relative space-y-6 before:absolute before:inset-0 before:ml-[1.125rem] before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-0.5 before:bg-gradient-to-b before:from-transparent before:via-border before:to-transparent">
        {STAGES.map((stage, idx) => {
          const isCompleted = currentIndex > idx;
          const isActive = currentIndex === idx;
          const isPending = currentIndex < idx;

          return (
            <motion.div
              key={stage.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.1 }}
              className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group is-active"
            >
              {/* Icon */}
              <div
                className={`flex items-center justify-center w-9 h-9 rounded-full border-2 bg-card shrink-0 md:order-1 md:group-odd:-translate-x-1/2 md:group-even:translate-x-1/2 shadow-sm z-10 transition-colors duration-300 ${
                  isActive ? "border-primary text-primary" : 
                  isCompleted ? "border-green-500 text-green-500" : "border-border text-muted-foreground"
                }`}
              >
                {isActive ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : isCompleted ? (
                  <CheckCircle2 className="w-5 h-5" />
                ) : (
                  <Circle className="w-4 h-4" />
                )}
              </div>

              {/* Content Box */}
              <div className={`w-[calc(100%-3rem)] md:w-[calc(50%-2.5rem)] p-4 rounded-xl border transition-all duration-300 ${
                isActive ? "bg-primary/5 border-primary/20 shadow-md" : 
                isCompleted ? "bg-card border-border/50 opacity-80" : "bg-transparent border-transparent opacity-40"
              }`}>
                <div className="flex flex-col">
                  <span className={`font-semibold text-sm ${isActive ? "text-primary" : "text-foreground"}`}>
                    {stage.label}
                  </span>
                  <span className="text-xs text-muted-foreground mt-1">
                    {stage.description}
                  </span>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { useEffect, useState } from "react";

interface CircularProgressProps {
  value: number;
  size?: number;
  strokeWidth?: number;
  color?: string;
  label?: string;
}

export function CircularProgress({
  value,
  size = 120,
  strokeWidth = 8,
  color = "text-primary",
  label,
}: CircularProgressProps) {
  const [animatedValue, setAnimatedValue] = useState(0);
  const radius = (size - strokeWidth) / 2;
  const circumference = radius * 2 * Math.PI;
  const offset = circumference - (animatedValue / 100) * circumference;

  useEffect(() => {
    const timeout = setTimeout(() => setAnimatedValue(value), 300);
    return () => clearTimeout(timeout);
  }, [value]);

  return (
    <div className="relative flex flex-col items-center justify-center">
      <svg width={size} height={size} className="transform -rotate-90">
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke="currentColor"
          strokeWidth={strokeWidth}
          fill="transparent"
          className="text-muted opacity-20"
        />
        <motion.circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke="currentColor"
          strokeWidth={strokeWidth}
          fill="transparent"
          strokeDasharray={circumference}
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset: offset }}
          transition={{ duration: 1.5, ease: "easeOut" }}
          className={color}
          strokeLinecap="round"
        />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
        <span className="text-3xl font-bold tracking-tighter">
          {Math.round(animatedValue)}
        </span>
        {label && <span className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold mt-1">{label}</span>}
      </div>
    </div>
  );
}

"use client";

import { FinalReport } from "@/services/ai/state";
import { CircularProgress } from "../ui/CircularProgress";
import { ShieldCheck, TrendingUp, AlertTriangle } from "lucide-react";

export function InvestmentVerdictCard({ report }: { report: FinalReport }) {
  const { finalRecommendation, investmentScore, confidenceScore, executiveSummary } = report;

  const isInvest = finalRecommendation === "Invest";
  const isHold = finalRecommendation === "Hold";

  const recommendationColor = isInvest 
    ? "text-green-500 bg-green-500/10 border-green-500/20" 
    : isHold 
    ? "text-yellow-500 bg-yellow-500/10 border-yellow-500/20" 
    : "text-red-500 bg-red-500/10 border-red-500/20";

  const RecommendationIcon = isInvest ? TrendingUp : isHold ? ShieldCheck : AlertTriangle;

  return (
    <div className="relative overflow-hidden rounded-3xl border border-border bg-card shadow-sm p-8 flex flex-col md:flex-row gap-8 items-center">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-border to-transparent opacity-50" />

      <div className="flex-1 space-y-6">
        <div>
          <h2 className="text-sm uppercase tracking-widest text-muted-foreground font-semibold mb-2">Final Verdict</h2>
          <div className={`inline-flex items-center gap-2 px-4 py-2 rounded-full border ${recommendationColor}`}>
            <RecommendationIcon className="w-5 h-5" />
            <span className="text-xl font-bold tracking-tight">{finalRecommendation}</span>
          </div>
        </div>

        <div>
          <h3 className="text-lg font-semibold mb-2">Executive Summary</h3>
          <p className="text-muted-foreground leading-relaxed">
            {executiveSummary}
          </p>
        </div>
      </div>

      <div className="flex gap-6 md:border-l md:border-border/50 md:pl-8">
        <CircularProgress 
          value={investmentScore} 
          label="Score" 
          color={isInvest ? "text-green-500" : isHold ? "text-yellow-500" : "text-red-500"} 
        />
        <CircularProgress 
          value={confidenceScore} 
          label="Confidence" 
          color="text-primary" 
        />
      </div>
    </div>
  );
}

"use client";

import { FinancialAnalysis } from "@/services/ai/state";
import { DollarSign, LineChart, Activity, Briefcase } from "lucide-react";

export function FinancialMetricsGrid({ data }: { data: FinancialAnalysis }) {
  const metrics = [
    { title: "Revenue Growth", value: data.revenueGrowthTrends, icon: TrendingUpIcon },
    { title: "Profitability", value: data.profitability, icon: DollarSign },
    { title: "Operating Margins", value: data.operatingMargins, icon: Activity },
    { title: "Debt Levels", value: data.debtLevels, icon: Briefcase },
    { title: "Cash Flow", value: data.cashFlowQuality, icon: LineChart },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {metrics.map((metric, idx) => (
        <div key={idx} className="bg-card border border-border/50 rounded-xl p-5 hover:border-border transition-colors">
          <div className="flex items-center gap-3 mb-3">
            <div className="p-2 bg-primary/5 rounded-lg text-primary">
              <metric.icon className="w-4 h-4" />
            </div>
            <h4 className="font-semibold text-sm">{metric.title}</h4>
          </div>
          <p className="text-sm text-muted-foreground leading-relaxed line-clamp-3">
            {metric.value}
          </p>
        </div>
      ))}
      <div className="bg-card border border-border/50 rounded-xl p-5 hover:border-border transition-colors">
         <div className="flex items-center gap-3 mb-3">
            <div className="p-2 bg-primary/5 rounded-lg text-primary">
              <Activity className="w-4 h-4" />
            </div>
            <h4 className="font-semibold text-sm">Overall Strength</h4>
          </div>
          <p className="text-sm text-muted-foreground leading-relaxed line-clamp-3">
            {data.overallFinancialStrength}
          </p>
      </div>
    </div>
  );
}

function TrendingUpIcon(props: any) {
  return (
    <svg
      {...props}
      xmlns="http://www.w3.org/2000/svg"
      width="24"
      height="24"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <polyline points="22 7 13.5 15.5 8.5 10.5 2 17" />
      <polyline points="16 7 22 7 22 13" />
    </svg>
  );
}

"use client";

import { SwotAnalysis } from "@/services/ai/state";
import { Dumbbell, HeartCrack, Zap, ShieldAlert } from "lucide-react";

export function SwotGrid({ data }: { data: SwotAnalysis }) {
  const sections = [
    { title: "Strengths", items: data.strengths, icon: Dumbbell, color: "text-green-500", bg: "bg-green-500/5", border: "border-green-500/10" },
    { title: "Weaknesses", items: data.weaknesses, icon: HeartCrack, color: "text-red-500", bg: "bg-red-500/5", border: "border-red-500/10" },
    { title: "Opportunities", items: data.opportunities, icon: Zap, color: "text-blue-500", bg: "bg-blue-500/5", border: "border-blue-500/10" },
    { title: "Threats", items: data.threats, icon: ShieldAlert, color: "text-orange-500", bg: "bg-orange-500/5", border: "border-orange-500/10" },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
      {sections.map((section, idx) => (
        <div key={idx} className={`${section.bg} border ${section.border} rounded-2xl p-5`}>
          <div className={`flex items-center gap-2 mb-4 ${section.color}`}>
            <section.icon className="w-5 h-5" />
            <h4 className="font-semibold">{section.title}</h4>
          </div>
          <ul className="space-y-3">
            {section.items.map((item, i) => (
