import { ChatGoogleGenerativeAI } from "@langchain/google-genai";

/** Shared LLM factory – always server-side only. */
export const getLLM = (temperature = 0) => {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) throw new Error("GEMINI_API_KEY environment variable is not set.");
  return new ChatGoogleGenerativeAI({
    model: "gemini-1.5-pro",
    maxOutputTokens: 8192,
    temperature,
    apiKey,
  });
};

/** Structured Tavily search – native fetch, no @langchain/community dependency. */

interface TavilyResult {
  title: string;
  url: string;
  content: string;
}

interface TavilyResponse {
  results?: TavilyResult[];
}

export const getTavilySearchTool = (maxResults = 5) => {
  return {
    invoke: async (query: string): Promise<string> => {
      const apiKey = process.env.TAVILY_API_KEY;
      if (!apiKey) {
        throw new Error("TAVILY_API_KEY environment variable is not set.");
      }

      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 15_000); // 15s timeout

      try {
        const response = await fetch("https://api.tavily.com/search", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            api_key: apiKey,
            query,
            search_depth: "basic",
            include_answer: false,
            include_images: false,
            include_raw_content: false,
            max_results: maxResults,
          }),
          signal: controller.signal,
        });

        if (!response.ok) {
          throw new Error(`Tavily API returned ${response.status}: ${response.statusText}`);
        }

        const data = (await response.json()) as TavilyResponse;
        return JSON.stringify(data.results ?? []);
      } catch (err: unknown) {
        if (err instanceof Error && err.name === "AbortError") {
          throw new Error("Tavily search timed out after 15 seconds.");
        }
        throw err;
      } finally {
        clearTimeout(timeout);
      }
    },
  };
};

import { GraphState } from "../state";
import { getLLM } from "../llm";
import { PROMPTS } from "../prompts";
import { companyResearchSchema } from "../schema";
import { SystemMessage } from "@langchain/core/messages";
import { getTavilySearchTool } from "../tools/tavily";

export const companyResearchNode = async (
  state: GraphState,
): Promise<Partial<GraphState>> => {
  const companyName = state.normalizedCompanyName ?? state.companyName;
  try {
    const searchTool = getTavilySearchTool(5);
    const searchResult = await searchTool.invoke(
      `${companyName} company overview: founded, CEO, headquarters, business model, products, revenue, industry sector`,
    );

    const structuredLlm = getLLM(0.1).withStructuredOutput(companyResearchSchema, {
      name: "company_research",
    });

    const response = await structuredLlm.invoke([
      new SystemMessage(PROMPTS.companyResearch.replace("{companyName}", companyName)),
      { role: "user", content: `Web Search Results:\n${searchResult}` },
    ]);

    return { researchData: response };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : "Unknown error";
    console.error("[companyResearchNode]", message);
    return {
      errors: [...(state.errors ?? []), `Company research failed: ${message}`],
    };
  }
};

import { z } from "zod";
import { GraphState } from "../state";
import { getLLM } from "../llm";
import { PROMPTS } from "../prompts";
import { SystemMessage } from "@langchain/core/messages";

const validationSchema = z.object({
  isValid: z.boolean(),
  normalizedCompanyName: z.string().optional(),
  error: z.string().optional(),
});

export const validateInputNode = async (
  state: GraphState,
): Promise<Partial<GraphState>> => {
  const raw = state.companyName?.trim();
  if (!raw) {
    return { isValid: false, errors: ["Company name cannot be empty."] };
  }

  try {
    const structuredLlm = getLLM(0).withStructuredOutput(validationSchema, {
      name: "validate_company",
    });

    const response = await structuredLlm.invoke([
      new SystemMessage(PROMPTS.validateInput),
      { role: "user", content: `Company Input: ${raw}` },
    ]);

    if (!response.isValid) {
      return {
        isValid: false,
        errors: [response.error ?? "The provided company name could not be recognized."],
      };
    }

    return {
      isValid: true,
      normalizedCompanyName: response.normalizedCompanyName ?? raw,
    };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : "Unknown error";
    console.error("[validateInputNode]", message);
    return {
      isValid: false,
      errors: [`Input validation failed: ${message}`],
    };
  }
};

import { GraphState } from "../state";
import { getLLM } from "../llm";
import { PROMPTS } from "../prompts";
import { financialAnalysisSchema } from "../schema";
import { SystemMessage } from "@langchain/core/messages";
