import { NextRequest, NextResponse } from "next/server";
import { investmentResearchGraph } from "@/services/ai/graph";

export async function POST(req: NextRequest) {
  // ── 1. Parse & validate request body ─────────────────────────────────────
  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json(
      { error: "Malformed JSON in request body." },
      { status: 400 },
    );
  }

  if (
    typeof body !== "object" ||
    body === null ||
    !("companyName" in body) ||
    typeof (body as Record<string, unknown>).companyName !== "string"
  ) {
    return NextResponse.json(
      { error: "Request body must include a non-empty string field: companyName." },
      { status: 400 },
    );
  }

  const companyName = ((body as Record<string, unknown>).companyName as string).trim();
  if (!companyName) {
    return NextResponse.json(
      { error: "companyName must not be empty." },
      { status: 400 },
    );
  }

  // ── 2. Execute the LangGraph workflow ────────────────────────────────────
  try {
    const config = { configurable: { thread_id: crypto.randomUUID() } };
    const finalState = await investmentResearchGraph.invoke(
      { companyName, errors: [] },
      config,
    );

    // ── 3. Handle validation failure (unrecognised company) ─────────────────
    if (!finalState.isValid) {
      return NextResponse.json(
        {
          error: "Company validation failed.",
          details: Array.isArray(finalState.errors) ? finalState.errors : [],
        },
        { status: 422 },
      );
    }

    // ── 4. Handle partial / incomplete report ────────────────────────────────
    if (!finalState.finalReport) {
      const errors = Array.isArray(finalState.errors) ? finalState.errors : [];
      console.warn("[/api/analyze] Graph completed without a final report.", errors);
      return NextResponse.json(
        {
          error: "The analysis pipeline could not produce a complete report.",
          details: errors,
        },
        { status: 500 },
      );
    }

    // ── 5. Success ────────────────────────────────────────────────────────────
    return NextResponse.json(finalState.finalReport, { status: 200 });
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : "An unexpected error occurred.";
    // Mask internal details — only log server-side
    console.error("[/api/analyze] Unhandled error:", err);
    return NextResponse.json(
      { error: "Internal server error. Please try again later." },
      { status: 500 },
    );
  }
}

import { create } from "zustand";
import type { FinalReport } from "@/services/ai/state";

// ── Loading stage type ──────────────────────────────────────────────────────
export type LoadingStage =
  | "idle"
  | "validating"
  | "researching"
  | "financials"
  | "news"
  | "swot"
  | "risk"
  | "decision"
  | "report"
  | "complete"
  | "error";

// ── Store interface ─────────────────────────────────────────────────────────
interface ResearchStore {
  query: string;
  isAnalyzing: boolean;
  loadingStage: LoadingStage;
  error: string | null;
  report: FinalReport | null;

  analyzeCompany: (companyName: string) => Promise<void>;
  reset: () => void;
  cancelRequest: () => void;
}

// ── Stage progression (mirrors graph nodes) ─────────────────────────────────
const STAGES: LoadingStage[] = [
  "validating",
  "researching",
  "financials",
  "news",
  "swot",
  "risk",
  "decision",
  "report",
  "complete",
];

/** Module-level ref so abort works even after re-renders */
let _abortController: AbortController | null = null;
let _stageInterval: ReturnType<typeof setInterval> | null = null;

const clearStageInterval = () => {
  if (_stageInterval !== null) {
    clearInterval(_stageInterval);
    _stageInterval = null;
  }
};

// ── Store ────────────────────────────────────────────────────────────────────
export const useResearchStore = create<ResearchStore>((set, get) => ({
  query: "",
  isAnalyzing: false,
  loadingStage: "idle",
  error: null,
  report: null,

  cancelRequest: () => {
    _abortController?.abort();
    _abortController = null;
    clearStageInterval();
    set({ isAnalyzing: false, loadingStage: "idle" });
  },

  reset: () => {
    get().cancelRequest();
    set({ query: "", error: null, report: null, loadingStage: "idle" });
  },

  analyzeCompany: async (companyName: string) => {
    // Cancel any in-flight request before starting a new one
    get().cancelRequest();

    set({
      isAnalyzing: true,
      loadingStage: "validating",
      error: null,
      report: null,
      query: companyName,
    });

    _abortController = new AbortController();

    // Simulate progressive stage display (≈5s per node; real API takes 40–60s)
    let stageIndex = 0;
    _stageInterval = setInterval(() => {
      stageIndex += 1;
      // Stay one before 'complete' — final stage set on API return
      if (stageIndex < STAGES.length - 1) {
        set({ loadingStage: STAGES[stageIndex] });
      } else {
        clearStageInterval();
      }
    }, 5_000);

    try {
      const res = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ companyName }),
        signal: _abortController.signal,
      });

      clearStageInterval();

      const data: unknown = await res.json();

      if (!res.ok) {
        const errData = data as { error?: string; details?: string[] };
        const message =
          errData.error ??
          (Array.isArray(errData.details) ? errData.details[0] : undefined) ??
          "Analysis failed. Please try again.";
        throw new Error(message);
      }

      set({
        report: data as FinalReport,
        loadingStage: "complete",
        isAnalyzing: false,
      });
    } catch (err: unknown) {
      clearStageInterval();

      // Silently handle user-initiated cancellations
      if (err instanceof Error && err.name === "AbortError") return;

      const message =
        err instanceof Error ? err.message : "Failed to connect to the server.";

      set({
        error: message,
        loadingStage: "error",
        isAnalyzing: false,
      });
    } finally {
      _abortController = null;
    }
  },
}));

"use client";

import { Search, Loader2, ArrowRight, X } from "lucide-react";
import { useCallback, useRef, KeyboardEvent, useState, useEffect } from "react";
import { useResearchStore } from "@/store/useResearchStore";

const EXAMPLE_COMPANIES = [
  "NVIDIA",
  "Apple",
  "Tesla",
  "Reliance Industries",
  "Zomato",
  "Microsoft",
  "Amazon",
  "Infosys",
];

interface SearchBarProps {
  /** Optionally pre-fill the query (e.g., from example company click) */
  initialQuery?: string;
  onQueryChange?: (q: string) => void;
}

export function SearchBar({ initialQuery = "", onQueryChange }: SearchBarProps) {
  const [query, setQuery] = useState(initialQuery);
  const inputRef = useRef<HTMLInputElement>(null);
  const { analyzeCompany, isAnalyzing, reset } = useResearchStore();

  // Sync when parent changes initialQuery (e.g., example chip click)
  useEffect(() => {
    setQuery(initialQuery);
    if (initialQuery) inputRef.current?.focus();
  }, [initialQuery]);

  const handleChange = (val: string) => {
    setQuery(val);
    onQueryChange?.(val);
  };

  const handleSubmit = useCallback(() => {
    const trimmed = query.trim();
    if (!trimmed || isAnalyzing) return;
    analyzeCompany(trimmed);
  }, [query, isAnalyzing, analyzeCompany]);

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") handleSubmit();
    if (e.key === "Escape") handleChange("");
  };

  const handleClear = () => {
    handleChange("");
    reset();
    inputRef.current?.focus();
  };

  return (
    <div
      className="relative group w-full max-w-2xl mx-auto"
      role="search"
      aria-label="Company search"
    >
      {/* Glow effect */}
      <div
        aria-hidden="true"
        className="absolute inset-0 bg-gradient-to-r from-primary/15 to-primary/5 rounded-2xl blur-xl opacity-0 group-hover:opacity-60 group-focus-within:opacity-80 transition-opacity duration-500 pointer-events-none"
      />

      <div className="relative flex w-full items-center bg-card border border-border/60 rounded-2xl p-2 shadow-sm transition-all duration-200 focus-within:shadow-lg focus-within:border-primary/50">
        <Search className="ml-3 h-5 w-5 text-muted-foreground flex-shrink-0" aria-hidden="true" />

        <input
          ref={inputRef}
          id="company-search"
          type="text"
          role="searchbox"
          aria-label="Enter company name"
          value={query}
          onChange={(e) => handleChange(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={isAnalyzing}
          placeholder="Search a company (e.g., NVIDIA, Apple, Reliance)…"
          autoComplete="off"
          className="flex-1 bg-transparent border-none outline-none px-4 py-3 text-foreground placeholder:text-muted-foreground/60 disabled:opacity-50 text-base sm:text-lg min-w-0"
        />

        {query && !isAnalyzing && (
          <button
            onClick={handleClear}
            aria-label="Clear search"
            className="mr-2 p-1 rounded-md text-muted-foreground hover:text-foreground hover:bg-secondary/60 transition-colors"
          >
            <X className="h-4 w-4" />
          </button>
        )}

        <button
          onClick={handleSubmit}
          disabled={!query.trim() || isAnalyzing}
          aria-label={isAnalyzing ? "Analyzing…" : "Analyze company"}
          className="flex items-center justify-center bg-primary text-primary-foreground h-11 w-11 rounded-xl transition-all duration-150 hover:opacity-90 hover:scale-105 active:scale-95 disabled:opacity-40 disabled:hover:scale-100 disabled:cursor-not-allowed flex-shrink-0"
        >
          {isAnalyzing ? (
            <Loader2 className="h-5 w-5 animate-spin" aria-hidden="true" />
          ) : (
            <ArrowRight className="h-5 w-5" aria-hidden="true" />
          )}
        </button>
      </div>
    </div>
  );
}

